3426   /// blocks. The accesses are casted to \p BlockTy.
3427   template <typename BlockTy, typename T>
3428   static auto blocksOnly(const T &Range) {
3429     // Create BaseTy with correct const-ness based on BlockTy.
3430     using BaseTy = std::conditional_t<std::is_const<BlockTy>::value,
3431                                       const VPBlockBase, VPBlockBase>;
3432 
3433     // We need to first create an iterator range over (const) BlocktTy & instead
3434     // of (const) BlockTy * for filter_range to work properly.
3435     auto Mapped =
